-- Poems batch 167
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fd306524-bb0d-4555-b368-f17f17c44898','次韻僉判丈','趙蕃','宋','宋诗','song-poetry','','[]','芳遊忽忽未多諧，芳事匆匆已覆盃。',64,'全唐诗/poet.song.166000.json','["芳遊忽忽未多諧，芳事匆匆已覆盃。", "可恨海棠經雨盡，尚餘芍藥殿春開。", "公能有意巾車出，我亦乘閑步屧來。", "倚杖看花從迫窄，未妨隨處一徘徊。"]'),
('d4d2e5b9-9572-496d-a21b-9202c5f2d5a3','次韻斯遠見寄','趙蕃','宋','宋诗','song-poetry','','[]','春今半歷未知春，可奈昏昏晝復晨。',64,'全唐诗/poet.song.166000.json','["春今半歷未知春，可奈昏昏晝復晨。", "藥裹豈能知許病，詩囊亦覺頓成貧。", "羲和送日何其怯，天女司花不解神。", "何但子行無所詣，我懷端亦在湖漘。"]'),
('5005591e-7ff7-4f2f-a109-b4d38c67568b','次韻何叔信','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','苔蘚斑斑過雨廊，菱荷獵獵晚秋鄉。',64,'全唐诗/poet.song.166000.json','["苔蘚斑斑過雨廊，菱荷獵獵晚秋鄉。", "廬山大似要元亮，江夏安能隠戴良。", "酒遇諸豪君可敵，詩逢二妙我無長。", "昔何勇銳今何怯，暢敘深孤詠與觴。"]'),
('c45e95d3-4c54-4601-98f5-8c6a834487fa','趙龍泉惠書及和三詩且用孫溫叟韻作詩見勞次韻','趙蕃','宋','宋诗','song-poetry','','[]','一紙翻翻正復頗，數詩兼與問云何。',64,'全唐诗/poet.song.166000.json','["一紙翻翻正復頗，數詩兼與問云何。", "敢言少日期耕籍，但道今年學荷戈。", "已辦向人腰爲折，更愁逢彼怒成訶。", "知時未暇傷鵜鴂，撥穀惟思和九歌。"]'),
('d2a38814-399f-49da-943f-52380b0d09fc','次韻何叔信劉元之魏昭父','趙蕃','宋','宋诗','song-poetry','','[]','往事悠悠誰悼屈，土風往往但爭舟。',64,'全唐诗/poet.song.166000.json','["往事悠悠誰悼屈，土風往往但爭舟。", "兒童助勇競拍手，鷗鷺驚飛皆落流。", "倦客歸心思鷁首，壯年科第慕龍頭。", "詩中具見飄飄意，如我將搴杜若洲。"]'),
('5b038d32-bd9f-46ad-b604-a46723ce55cb','次韻王駒父','趙蕃','宋','宋诗','song-poetry','','[]','誰歟覓我更貽詩，欲報翻慚思苦遲。',64,'全唐诗/poet.song.166000.json','["誰歟覓我更貽詩，欲報翻慚思苦遲。", "自古結交真有道，可能隨俗似凡兒。", "功名有命寧須此，貧賤從吾欲怨誰。", "我亦與君俱白髮，世間冷煖要當知。"]'),
('89340fec-7ad4-49b7-89bc-28763921fab2','次韻葉德章見示','趙蕃','宋','宋诗','song-poetry','','[]','窮冬未省見梅班，故里何繇報竹安。',64,'全唐诗/poet.song.166000.json','["窮冬未省見梅班，故里何繇報竹安。", "歸意寧須卜以决，衰顔不待鏡頻看。", "交情謝子來今雨，節物娛予後苦寒。", "獨苦更憐終漫興，不如骫骳得天歡。"]'),
('8aad879b-4233-411e-aadb-78bb4b4a91e7','次韻嚴從禮兼簡明叔','趙蕃','宋','宋诗','song-poetry','','[]','晚風吹雨過前灣，載酒誰歟起病顔。',64,'全唐诗/poet.song.166000.json','["晚風吹雨過前灣，載酒誰歟起病顔。", "政爾交遊能不乏，故知酬唱未令慳。", "只今衝口從俱錄，異日蕪詞合細刪。", "如我論材真款段，兩君駿足本天閑。"]'),
('53662aa3-c7f8-41fa-a447-cdae250d7dc4','在伯用沅陵韻見貽次韻','趙蕃','宋','宋诗','song-poetry','','[]','一代數人君有傳，九原可作我無緣。',64,'全唐诗/poet.song.166000.json','["一代數人君有傳，九原可作我無緣。", "頗思燈火親餘暇，却恨江湖枉過年。", "載辱新詩爲永好，絕知高義有哀憐。", "官閑借問忙何事，日日經營作和篇。"]'),
('a4c7a73e-6938-4752-9df3-cdf09c0051b3','王亢宗自玉山寄二詩次韻報之  其一','趙蕃','宋','宋诗','song-poetry','','[]','孰計還家底許居，政猶秋雨墮芙蕖。',64,'全唐诗/poet.song.166000.json','["孰計還家底許居，政猶秋雨墮芙蕖。", "只今敢謂歲不與，自省從來術故疏。", "芻秣可憐哀病顙，江湖寧得欠舂鋤。", "小舟已向山陰去，但遣和詩慵報書。"]'),
('2941e4ca-d2bc-4eb6-b424-59bddbcf896d','王亢宗自玉山寄二詩次韻報之  其二','趙蕃','宋','宋诗','song-poetry','','[]','一官偶落大江西，名姓摧藏肯願知。',64,'全唐诗/poet.song.166000.json','["一官偶落大江西，名姓摧藏肯願知。", "取友但論詩好惡，逢人不說位高卑。", "殷勤媿子能相覓，邂逅起予還有詩。", "是物解窮無苦嗜，恐教盛業枉明時。"]'),
('8d2e5609-1912-4946-8a77-4a29c1e2abf2','游宋衡送示登明錄詩卷次韻併呈同賦諸公','趙蕃','宋','宋诗','song-poetry','','[]','赤氣排空勢且然，簿書何急又堆前。',64,'全唐诗/poet.song.166000.json','["赤氣排空勢且然，簿書何急又堆前。", "忽來疎雨微雲句，置以清冰寒露邊。", "想見坐中皆玉雪，更知眼界足風烟。", "雖然此樂宜輸我，公等談經合細旃。"]'),
('fbe934d0-a968-4dc7-baa8-6e02550bee10','次韻和仲留別之什','趙蕃','宋','宋诗','song-poetry','','[]','政怯離憂致感傷，要煩杯酒洗蒼茫。',64,'全唐诗/poet.song.166000.json','["政怯離憂致感傷，要煩杯酒洗蒼茫。", "湖山已負二樓勝，風雨還并一笑妨。", "邂逅苦爲輕此別，漂流重見定何方。", "人歸帝所門非邃，江出岷山道苦長。"]'),
('5df2233a-79da-4de3-bbbd-b1c50eab1f71','昨日過仲威不值作詩來謝因次其韻併呈明叔','趙蕃','宋','宋诗','song-poetry','','[]','故山端可計焉終，孰遣求官自取窮。',64,'全唐诗/poet.song.166000.json','["故山端可計焉終，孰遣求官自取窮。", "詩遇二豪真勝己，鬢驚霜白驗成翁。", "醒狂在昔人增益，間闊於今安取豐。", "邂逅過君無厭數，異時相遠念難同。"]'),
('228297ef-daf9-4759-b4da-fcff75465e10','次韻成父','趙蕃','宋','宋诗','song-poetry','','[]','山經立壁動危情，路入懸崖作峭行。',64,'全唐诗/poet.song.166000.json','["山經立壁動危情，路入懸崖作峭行。", "雨露正昏當晝黑，瀑泉倒瀉助波驚。", "萬無一理可至寇，十有九家空避兵。", "媿子遠來端有意，更開詩篋對燈檠。"]'),
('13a50b6c-9f0f-46b1-8437-5b57cfc7e5a5','次韻在伯夏夜獨坐見懷之作','趙蕃','宋','宋诗','song-poetry','','[]','暑氣侵人抵病中，闕然求舊管城公。',64,'全唐诗/poet.song.166000.json','["暑氣侵人抵病中，闕然求舊管城公。", "相逢共說山中月，有贈忽來天未風。", "君向離騷熟蘭芷，我於爾雅昧魚蟲。", "縱令酒盞能頻把，孰若詩筒得屢通。"]'),
('4bbb1eee-abe0-49e7-b041-b6527483a18d','次韻審知十七夜','趙蕃','宋','宋诗','song-poetry','','[]','風月當佳可易捐，共須重立虎溪邊。',64,'全唐诗/poet.song.166000.json','["風月當佳可易捐，共須重立虎溪邊。", "天于變化自奇手，人欲追摹真强憐。", "牢落朱絃千載下，凄凉青鬢十年前。", "放歌莫作商聲發，驚起沙頭鷗鷺眠。"]'),
('72059177-506d-4008-bd02-29fceb43b4d7','簽判丈讀曾文清公坐聞幽鳥語勝與俗人言之句感之爲長句蕃謹次韻同賦','趙蕃','宋','宋诗','song-poetry','','[]','客到真成罷送迎，顧于禽鳥未忘情。',64,'全唐诗/poet.song.166000.json','["客到真成罷送迎，顧于禽鳥未忘情。", "雨邊鳩婦離羣去，烟裏竹鷄相應鳴。", "肯對子規愁百草，願令反舌遂無聲。", "支頤獨愛提壺語，似念田間有餉耕。"]'),
('2bb8262b-2374-441d-8e18-7cd39a46c596','簽判丈再枉長句次韻','趙蕃','宋','宋诗','song-poetry','','[]','紛紛紅蘂一番春，寂寂清陰幾處新。',64,'全唐诗/poet.song.166000.json','["紛紛紅蘂一番春，寂寂清陰幾處新。", "陌上風光屬游女，林間觴詠聽幽人。", "經旬便作治聾飲，涉七還當脩禊辰。", "無事相過勿相遠，具宜從率亦從真。"]'),
('5dbd5a5c-879a-458a-a6e1-90b9d36e4cd1','次韻歐陽全真送行','趙蕃','宋','宋诗','song-poetry','','[]','幾欲歸休反服初，契論今昔更憐渠。',64,'全唐诗/poet.song.166000.json','["幾欲歸休反服初，契論今昔更憐渠。", "非關造物相料理，自是吾儕計闊疎。", "似我端宜吏刀筆，如君久合召嚴徐。", "胡然更作丁寧語，道所經行覓細書。"]'),
('9969c6a4-11c9-435e-84ae-564fac1bfaba','次韻李子永見貽','趙蕃','宋','宋诗','song-poetry','','[]','何能辛苦歎人窮，况復經行覓句工。',64,'全唐诗/poet.song.166000.json','["何能辛苦歎人窮，况復經行覓句工。", "平日相思在天末，今年遠別遂湘中。", "饑寒似我誰驅迫，人物如公孰長雄。", "蕙帳山人久寂寞，曾何臺省欠諸公。"]'),
('e38aecc0-d2b5-4523-a43b-bb2dd66b137f','次韻孫溫叟問訊之韻','趙蕃','宋','宋诗','song-poetry','','[]','拊髀嘗聞問牧頗，祇今時勢定如何。',64,'全唐诗/poet.song.166000.json','["拊髀嘗聞問牧頗，祇今時勢定如何。", "要知絕惡思除本，莫爲輕降信倒戈。", "幕府似公猶不用，官曹如我政宜訶。", "兵傳家法檄愈疾，不但有詩皆可歌。"]'),
('9e9ff222-e6d8-461e-8c18-55f76cb80b3b','在伯用巴字韻垂示次韻以報','趙蕃','宋','宋诗','song-poetry','','[]','我詩音節變巫巴，君向風流守故家。',64,'全唐诗/poet.song.166000.json','["我詩音節變巫巴，君向風流守故家。", "剝啄未嫌驚夢蝶，吟哦惟恐到昏鴉。", "沅湘自昔皆因適，蠻左于今況雜華。", "豈不懷歸歸未遂，水痕還落岸頭沙。"]'),
('f3bb16f3-98a5-4f04-842f-9d0834b5a5a6','次韻希登送行之什','趙蕃','宋','宋诗','song-poetry','','[]','頻年頗覺困邅屯，勇意歸尋寂寞濱。',64,'全唐诗/poet.song.166000.json','["頻年頗覺困邅屯，勇意歸尋寂寞濱。", "去日屢移雖怕別，積霖成潦政迷津。", "浮生聚散不終免，一語丁寧惟愛身。", "來歲入關須早計，要期過我待王春。"]'),
('806fef79-ab64-4225-9a94-c32aa69f8ce6','楊錄事以僕與孫溫叟唱酬韻作詩見貽又用僕與吳夢與詩韻作詩贈夢與兼以見及併次韻二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','丹鳳哀鳴領九雛，雀飛飽食下平蕪。',64,'全唐诗/poet.song.166000.json','["丹鳳哀鳴領九雛，雀飛飽食下平蕪。", "寒窗擁褐茲晨卧，急鼓穿鞋舊日趨。", "客至渠能勞剝啄，賦成我豈寓烏無。", "說天更擬愚溪去，榮辱端知可罷呼。"]'),
('f5f25b74-bd9e-47be-b34f-3c38f939a8bf','楊錄事以僕與孫溫叟唱酬韻作詩見貽又用僕與吳夢與詩韻作詩贈夢與兼以見及併次韻二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','了知人事近天機，蒼狗斯須變白衣。',64,'全唐诗/poet.song.166000.json','["了知人事近天機，蒼狗斯須變白衣。", "逋客幾回驚鶴怨，弋人終日慕鴻飛。", "由來災怪自珠玉，不以賤貧安布韋。", "我鬢已霜君可料，况堪七十古來稀。"]'),
('9ceb6f41-00a5-4ca0-9c9f-d77beaf45592','次韻子耕去秋臨安歸途見過於玉山智門寺之作','趙蕃','宋','宋诗','song-poetry','','[]','不但乘舟亦跨鞍，道長無地問平安。',64,'全唐诗/poet.song.166000.json','["不但乘舟亦跨鞍，道長無地問平安。", "相逢只謾分襟速，既別方知聚首難。", "海內忘形今有幾，天隅獨在若爲寬。", "夜過林寺猶前日，詩到還成隔歲看。"]'),
('37a6f278-a5f9-4fdd-aefc-a62503acfdc5','過豐城訪甘叔異聞在曲江之磯頭庵放舟過之棹未及弭迎勞之詩已至次韻上呈','趙蕃','宋','宋诗','song-poetry','','[]','竟日江行歷抵尋，聳然高屋在深林。',64,'全唐诗/poet.song.166000.json','["竟日江行歷抵尋，聳然高屋在深林。", "夷猶未覺磯頭遠，下上方知磴級深。", "好句已從天上落，快談仍慰別來心。", "經行賸約重來見，嶺海他年無鴈音。"]'),
('215a4ef6-ef37-4436-bf5d-54dca18d02b7','次韻徐丞用韻見示','趙蕃','宋','宋诗','song-poetry','','[]','往將短木飾青黄，負此枯林歲久霜。',64,'全唐诗/poet.song.166000.json','["往將短木飾青黄，負此枯林歲久霜。", "窮爲多言慕柔舌，病因止酒制剛腸。", "交遊大抵要晚節，談笑可須空累觴。", "凈掃松階决流水，效予清坐亦何妨。"]'),
('a16026e7-604f-46e8-882b-84908e3044d6','次韻南澗韓先生二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','歲月侵尋兩鬢稀，駕言乃復歎多岐。',64,'全唐诗/poet.song.166000.json','["歲月侵尋兩鬢稀，駕言乃復歎多岐。", "陳詩故匪初來識，辱贈何堪謬取知。", "太息先生作今日，頓還諸老在當時。", "倦游已恨歸來晚，南澗潺湲日日思。"]'),
('601247e7-336e-4515-aff3-f4a506bc9920','次韻南澗韓先生二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','秋入園林日夜稀，慨然那復更臨岐。',64,'全唐诗/poet.song.166000.json','["秋入園林日夜稀，慨然那復更臨岐。", "暗中摸索非其物，海內流傳會有知。", "豈但文章振吾道，更蘄饑溺濟斯時。", "直聲舊著尚書履，召節行聞夜席思。"]'),
('2c346d1a-b870-4b35-a277-ee3f1719edd4','次韻李商叟見示','趙蕃','宋','宋诗','song-poetry','','[]','路熟江郊不待尋，每來真得慰余心。',64,'全唐诗/poet.song.166000.json','["路熟江郊不待尋，每來真得慰余心。", "新詩自作彈丸羨，舊帖不教魚蠹侵。", "莫嘆高山與流水，難迷美玉及精金。", "頻年浪作江湖走，從此冰溪得並吟。"]'),
('86103371-6839-498b-911d-5bfdc1778d41','簽判丈以新字韻作長句見贈次韻','趙蕃','宋','宋诗','song-poetry','','[]','剝啄無嗔叩戶頻，要聽論古誦詩新。',64,'全唐诗/poet.song.166000.json','["剝啄無嗔叩戶頻，要聽論古誦詩新。", "百年風雅久不作，一代典刑今有人。", "敢謂投心似膠漆，故知與世若參辰。", "如公接物何多得，豈復畏人嫌我貧。"]'),
('218d6b5c-be39-4be1-a356-66efda808ee2','次韻伯瑞叔驥常字韻','趙蕃','宋','宋诗','song-poetry','','[]','來往區區莫謾忙，轉頭還是俗相妨。',64,'全唐诗/poet.song.166000.json','["來往區區莫謾忙，轉頭還是俗相妨。", "題詩見子留人意，作客如家自我常。", "休嘆清明仍值雨，好於元巳趁還鄉。", "布衾木枕猶堪質，要似當年人姓陽。"]'),
('6844790b-487d-481a-933c-2fcb61818bcf','遠齋用常字韻見貽次韻','趙蕃','宋','宋诗','song-poetry','','[]','閑中未免和詩忙，忙裏偷閑莫自妨。',64,'全唐诗/poet.song.166000.json','["閑中未免和詩忙，忙裏偷閑莫自妨。", "一夢江山驚草草，半春風雨自常常。", "桃花落去空流水，燕子歸來非故鄉。", "世事多端付醇酎，我知公不愧平陽。"]'),
('9bb9092c-3f4b-4f72-86ee-3c9bc0a6868d','次韻遠齋夜飲舒嘯之作併呈坐間諸公','趙蕃','宋','宋诗','song-poetry','','[]','偶上坡亭底用扶，登臨於此記公初。',64,'全唐诗/poet.song.166000.json','["偶上坡亭底用扶，登臨於此記公初。", "不勝酒敵先齊敗，粗有詩資皆楚餘。", "出處絕知難逆計，從遊常恐易成疏。", "嘯揮邊騎數君事，我自欲安陶令廬。"]'),
('5eed8079-f49f-4c47-a7c8-ec2536b43bbe','次韻王進之雨中見懷并示詩卷','趙蕃','宋','宋诗','song-poetry','','[]','落落窮居無與徒，幾思短李及辛迂。',64,'全唐诗/poet.song.166000.json','["落落窮居無與徒，幾思短李及辛迂。", "別時尚欲題書寄，近處何須折簡呼。", "筆下烟雲寧取異，胸中丘壑本來殊。", "年侵病劇渾忘却，今日因君整舊模。"]'),
('4219788e-21ed-4e98-b472-fe2b7e043f00','次韻伯瑞見示并懷叔驥和叔','趙蕃','宋','宋诗','song-poetry','','[]','世情易作風沙散，我輩端知雪柏堅。',64,'全唐诗/poet.song.166000.json','["世情易作風沙散，我輩端知雪柏堅。", "不以翱翔鴻鵠與，遂忘寂寞鷺鷗邊。", "往來苕霅渾疑夢，邂逅瀟湘重足憐。", "何日笑呼賢伯仲，持螯剝芡大人前。"]'),
('32cf201d-6375-45d6-8ae0-a2339670ba6b','慈利簿樂思中自沅州考試回經過見之留以小酌既以詩來次韻','趙蕃','宋','宋诗','song-poetry','','[]','飄然一舸順流東，敏捷如鴻恨不同。',64,'全唐诗/poet.song.166000.json','["飄然一舸順流東，敏捷如鴻恨不同。", "爲我能留半日許，得君何翅一聯中。", "頗思著句記初識，已復枉詩醉古風。", "沅芷澧蘭元屬爾，既難衮衮又匆匆。"]'),
('e9ff507f-5664-4b1d-ba4d-e70c5b03fca2','次韻魏饒州用蕃唱酬詩卷最後一篇韻見贈之作','趙蕃','宋','宋诗','song-poetry','','[]','世紛往往競趨奇，半額真同慕廣眉。',64,'全唐诗/poet.song.166000.json','["世紛往往競趨奇，半額真同慕廣眉。", "我已自知成忤俗，公今豈亦故違時。", "解鞍屢辱留連飲，出袖仍蒙惠好詩。", "異縣絕疎親且故，相從且免問爲誰。"]'),
('a760a5b3-3a49-4839-8bab-8295502aa5a2','次韻李子永','趙蕃','宋','宋诗','song-poetry','','[]','詞源誰可障東之，今代謫仙仍有詩。',64,'全唐诗/poet.song.166000.json','["詞源誰可障東之，今代謫仙仍有詩。", "戲調猶能出平澹，意加每輒造瓌奇。", "白頭不用論新貴，黄卷惟應保素知。", "我恨從公十年晚，公寧於我亦深期。"]'),
('74d31b2d-6fcd-476e-95ad-ebad219fae24','次韻蕭之沈弟','趙蕃','宋','宋诗','song-poetry','','[]','外家人物盛東南，古已云然豈獨今。',64,'全唐诗/poet.song.166000.json','["外家人物盛東南，古已云然豈獨今。", "兄弟長懷未多識，江湖廼得話同心。", "豈知行日還先我，更枉長吟寫意深。", "別後相思回首處，山哀浦思有餘音。"]'),
('467cff8f-e57d-4bba-b23b-dc93f64c95cf','九日次韻斯遠去年是日同成父登半山亭見懷之什寄斯遠兼示成父','趙蕃','宋','宋诗','song-poetry','','[]','去歲修途度此晨，今年抱疾更漳濱。',64,'全唐诗/poet.song.166000.json','["去歲修途度此晨，今年抱疾更漳濱。", "官壺可醉難多致，城菊未開空屢巡。", "憶我有詩朝在手，思君何處暮傷神。", "遥知置酒登高者，回首西南只兩人。"]'),
('7b4378c0-00e2-4d32-920e-cf87f4bb0e61','在伯用銅字韻作詩復次韻二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','閉門憐我欠新功，下筆奇君有古風。',64,'全唐诗/poet.song.166000.json','["閉門憐我欠新功，下筆奇君有古風。", "豈但衆多窮草木，更能瑣細及魚蟲。", "昔人要作有爲者，後世多歸亡是公。", "歎息知堪幾寒暑，此身寧異物爲銅。"]'),
('b7463f75-502b-4175-9b3e-0c50b22878af','在伯用銅字韻作詩復次韻二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','凍筆題詩我故窮，憐君嗜好有同風。',64,'全唐诗/poet.song.166000.json','["凍筆題詩我故窮，憐君嗜好有同風。", "政如之越資章甫，何異當冰語夏蟲。", "既欲紛紛視兒子，可須衮衮羨諸公。", "雖然心氣無多廢，冰旱猶聞咎取銅。"]'),
('ad479f5a-b9cf-47c8-a97f-29faab636546','遠齋和示疏字韻四詩復用韻併呈子肅  其一','趙蕃','宋','宋诗','song-poetry','','[]','交舊年來寖作疎，兩翁頻肯問林居。',64,'全唐诗/poet.song.166000.json','["交舊年來寖作疎，兩翁頻肯問林居。", "兒時已誦天台賦，老去思傳祕府書。", "可使鸞凰棲枳棘，未應騏驥伏鹽車。", "時平自是功名晚，莫嘆江湖歲月除。"]'),
('7ec00009-248e-4a31-940c-01e2b42e2113','遠齋和示疏字韻四詩復用韻併呈子肅  其二','趙蕃','宋','宋诗','song-poetry','','[]','杖履過從每恨疎，何當有屋並門居。',64,'全唐诗/poet.song.166000.json','["杖履過從每恨疎，何當有屋並門居。", "我疑奇字就公問，公賦新詩令我書。", "無事晝棋仍夜酌，有時溪檝更山車。", "從教老色侵雙鬢，憑藉黄精爲茀除。"]'),
('f3fde562-4b8f-4ae3-9b46-407879411893','遠齋和示疏字韻四詩復用韻併呈子肅  其三','趙蕃','宋','宋诗','song-poetry','','[]','春風吹雨密還疎，門掩荒山數畝居。',64,'全唐诗/poet.song.166000.json','["春風吹雨密還疎，門掩荒山數畝居。", "換米但須居士屩，入都寧倚子公書。", "安貧自足容高枕，處事時應念覆車。", "所恨卜鄰非二仲，枉教三徑草頻除。"]'),
('0856598e-f3d1-420d-a077-64c7adbb20dc','遠齋和示疏字韻四詩復用韻併呈子肅  其四','趙蕃','宋','宋诗','song-poetry','','[]','竹經載伐似微疎，濩落猶能伴我居。',64,'全唐诗/poet.song.166000.json','["竹經載伐似微疎，濩落猶能伴我居。", "自分舉家長食粥，從渠厚祿絕無書。", "諸公漫仰蘇門隠，吾輩還羞李武車。", "役役眼前何所直，百年終向夢中除。"]'),
('d0bb3b61-aa3d-4265-a0d3-e29cefaed61d','上巳','趙蕃','宋','宋诗','song-poetry','','[]','朝來一雨快陰晴，東郊百鳥間關鳴。',64,'全唐诗/poet.song.166000.json','["朝來一雨快陰晴，東郊百鳥間關鳴。", "受風柳條不自惜，蘸水桃花可憐生。", "不見山陰蘭亭集，况乃長安麗人行。", "東西南北俱爲客，且送江頭返照明。"]'),
('7f494f78-0382-4532-82a3-91b74e4faf50','七盤嶺','趙蕃','宋','宋诗','song-poetry','','[]','遠近分濃淡，陰晴異蔽虧。',24,'全唐诗/poet.song.166000.json','["遠近分濃淡，陰晴異蔽虧。", "不知山路險，却幸馬行遲。"]'),
('d71cdbfc-d64a-4774-81e1-51fc86b575fe','澗舖嶺道中四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','近岫披晴霧，遥山縱雨雲。',24,'全唐诗/poet.song.166000.json','["近岫披晴霧，遥山縱雨雲。", "皚皚疑雪積，莽莽若江分。"]'),
('be40b86e-f5c5-421f-9189-e7cdbb28c184','澗舖嶺道中四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','嶺路縈紆合，泉流詰曲通。',24,'全唐诗/poet.song.166000.json','["嶺路縈紆合，泉流詰曲通。", "田毛無歲旱，山課與耕同。"]'),
('447bc74d-43a8-4c7b-b213-276f58110636','澗舖嶺道中四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','芋畝疑如蜀，山田更似閩。',24,'全唐诗/poet.song.166000.json','["芋畝疑如蜀，山田更似閩。", "祇看無廢地，寧復有閒民。"]'),
('709d63f1-318e-420e-9e33-9fb860f80c68','澗舖嶺道中四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','鉅竹差差合，青杉裊裊長。',24,'全唐诗/poet.song.166000.json','["鉅竹差差合，青杉裊裊長。", "人多表池檻，此乃亙山岡。"]'),
('1d40fe07-048f-4c3d-819d-db597621a31c','鐵笛亭','趙蕃','宋','宋诗','song-poetry','','[]','悵彼荆榛合，欣公杖履開。',24,'全唐诗/poet.song.166000.json','["悵彼荆榛合，欣公杖履開。", "倘非人隠異，何許笛飛來。"]'),
('cbd7ffba-c7b6-405a-b625-b521924cadf0','重午日摘枇杷薦酒因成兩絕句  其一','趙蕃','宋','宋诗','song-poetry','','[]','已載相如賦，還披杜老詩。',24,'全唐诗/poet.song.166000.json','["已載相如賦，還披杜老詩。", "團團自長葉，佳實欠纍纍。"]'),
('0dda9e56-82ca-4cbd-bd71-03339da28ef7','重午日摘枇杷薦酒因成兩絕句  其二','趙蕃','宋','宋诗','song-poetry','','[]','蜀酒能袪慮，昌陽解引年。',24,'全唐诗/poet.song.166000.json','["蜀酒能袪慮，昌陽解引年。", "楚君爲楚節，湘客念湘船。"]'),
('b0f84a78-694d-49fa-96c9-228a9a222d65','早題','趙蕃','宋','宋诗','song-poetry','','[]','欲雨雨似止，爲霜霜不成。',24,'全唐诗/poet.song.166000.json','["欲雨雨似止，爲霜霜不成。", "山雲解衣带，曉日掛銅鉦。"]'),
('8e1cdf45-fe5c-4d1b-8944-705291a521ab','雪觀','趙蕃','宋','宋诗','song-poetry','','[]','冷語可銷暑，昔人曾詠之。',24,'全唐诗/poet.song.166000.json','["冷語可銷暑，昔人曾詠之。", "我來登雪觀，政值綠陰時。"]'),
('387c29a5-e47d-4bc6-bc2b-47776692e75f','仁智堂','趙蕃','宋','宋诗','song-poetry','','[]','公乎仁且智，意託山與水。',24,'全唐诗/poet.song.166000.json','["公乎仁且智，意託山與水。", "唱道本龍門，遺塵仍栗里。"]'),
('8765b285-e470-45bc-8e3f-0c971f744269','白霧溪','趙蕃','宋','宋诗','song-poetry','','[]','霧雨猶疑合，槎頭不可窺。',24,'全唐诗/poet.song.166000.json','["霧雨猶疑合，槎頭不可窺。", "凶年走牲酒，平旦但茅茨。"]'),
('752220d7-9da9-4e48-9448-e110de2ebd92','晚歇溪上','趙蕃','宋','宋诗','song-poetry','','[]','愛此滄浪水，臨流坐寫詩。',24,'全唐诗/poet.song.166000.json','["愛此滄浪水，臨流坐寫詩。", "賦詩元未就，藉水發幽姿。"]'),
('3eb2f0cb-04ee-4047-b61c-a9aa8f775051','題西軒竹上','趙蕃','宋','宋诗','song-poetry','','[]','昔去無此屋，今茲更添竹。',24,'全唐诗/poet.song.166000.json','["昔去無此屋，今茲更添竹。", "吾輩固蕭閒，道人殊不俗。"]'),
('d601e4bc-e868-4ddf-a51e-4efbd7bbb94b','簡周允升三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','相逢亡恙外，第一問書堂。',24,'全唐诗/poet.song.166000.json','["相逢亡恙外，第一問書堂。", "爲說當年樹，如人出屋長。"]'),
('5ff4efc9-e50d-4b4e-8d6f-132d4773a6d5','簡周允升三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','春來多睡思，茗椀亦時須。',24,'全唐诗/poet.song.166000.json','["春來多睡思，茗椀亦時須。", "不敢家園乞，芭蕉有剩無。"]'),
('a0916639-7834-4ba3-9186-8e47f9ab13f6','簡周允升三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','君爲鄉校長，我政旅人居。',24,'全唐诗/poet.song.166000.json','["君爲鄉校長，我政旅人居。", "借屋元相近，相過莫放疎。"]'),
('043c344a-3fd3-44e0-9bfb-db6d0a4bb687','雲錦','趙蕃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖萬頃荷，護以隄千丈。',24,'全唐诗/poet.song.166000.json','["西湖萬頃荷，護以隄千丈。", "應詔待新辭，無爲戀盆盎。"]'),
('c28c6cc5-fe31-4f81-abda-27cbbdb6349f','感歸鳥','趙蕃','宋','宋诗','song-poetry','','[]','鳥雀知既夕，相逢如擇棲。',24,'全唐诗/poet.song.166000.json','["鳥雀知既夕，相逢如擇棲。", "嗟余獨何者，失侶自東西。"]'),
('6f370f16-efe8-4edb-adf6-ff25713f0aac','水樂','趙蕃','宋','宋诗','song-poetry','','[]','如抑又成揚，既考亦或鼓。',24,'全唐诗/poet.song.166000.json','["如抑又成揚，既考亦或鼓。", "始信石能言，無疑鈴解語。"]'),
('d639d940-af69-424d-adf7-9a8b4162eaed','雨游青原山二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','松竹青原剎，香燈七祖籤。',24,'全唐诗/poet.song.166000.json','["松竹青原剎，香燈七祖籤。", "窮通非所問，風雨暫成淹。"]'),
('962c0948-fb95-434b-a598-1ba5a1f64b82','雨游青原山二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','要作山中宿，悵無林下期。',24,'全唐诗/poet.song.166000.json','["要作山中宿，悵無林下期。", "摩挱魯公字，咀嚼豫章詩。"]'),
('9e09e640-1403-42d8-aa00-77294394b366','登亦好亭','趙蕃','宋','宋诗','song-poetry','','[]','風潮湧琉璃，露朵紛錦繡。',24,'全唐诗/poet.song.166000.json','["風潮湧琉璃，露朵紛錦繡。", "景物故不貧，詩篇況能富。"]'),
('52f4c87c-eb33-42fb-8c74-f4599d4075c4','冽泉','趙蕃','宋','宋诗','song-poetry','','[]','名士每名泉，一瓢寧取賢。',24,'全唐诗/poet.song.166000.json','["名士每名泉，一瓢寧取賢。", "道行期及物，爲澗定爲川。"]'),
('08344dcc-9863-47ca-b1b9-51580d0ed724','寒栖館','趙蕃','宋','宋诗','song-poetry','','[]','畦資搰搰功，爨藉丁丁力。',24,'全唐诗/poet.song.166000.json','["畦資搰搰功，爨藉丁丁力。", "但取茅蓋頭，不嗟家立壁。"]'),
('144e2796-28b4-412d-8c8c-77e11bea7a29','感鬻筍者','趙蕃','宋','宋诗','song-poetry','','[]','一寸葆萌茁，琅玕千尺姿。',24,'全唐诗/poet.song.166000.json','["一寸葆萌茁，琅玕千尺姿。", "園翁不知愛，採掘競刀錐。"]'),
