('7401979d-2a1a-46f2-931f-6cd247a2a69d','將至辰州走筆寄在伯教授二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','庭前甘菊都開否，記得去年同把觴。',32,'全唐诗/poet.song.166000.json','["庭前甘菊都開否，記得去年同把觴。", "相逢勞苦定愁絕，我哭途窮君悼亡。"]'),
('53adc7b5-aebc-4dcc-be35-d60398b42814','亭午欲過意復淒然偶引杯酒而沅陵丈送詩適至因走筆成兩絕併呈教授兄  其一','趙蕃','宋','宋诗','song-poetry','','[]','梅花玉立知何許，回首江東日暮雲。',32,'全唐诗/poet.song.166000.json','["梅花玉立知何許，回首江東日暮雲。", "白髮蕭蕭不歸去，顧徵蠻語作參軍。"]'),
('4c05ee3e-2abe-488f-a366-a1937b741576','亭午欲過意復淒然偶引杯酒而沅陵丈送詩適至因走筆成兩絕併呈教授兄  其二','趙蕃','宋','宋诗','song-poetry','','[]','寒廳冷日不能暄，杯酒時須手自溫。',32,'全唐诗/poet.song.166000.json','["寒廳冷日不能暄，杯酒時須手自溫。", "頼有好詩頻送我，能教病眼洗眵昏。"]'),
('2921ddef-5d8d-4ab6-b8cb-7baaddeb39ac','姑蘇道中','趙蕃','宋','宋诗','song-poetry','','[]','麥浪摇波柳映津，吳鄉春色見今晨。',32,'全唐诗/poet.song.166000.json','["麥浪摇波柳映津，吳鄉春色見今晨。", "欲將何以慰無頼，一酌濁醪如有神。"]'),
('1ff90612-046e-4bd4-8db8-089d303ff45b','早飯龍堂寺','趙蕃','宋','宋诗','song-poetry','','[]','櫸藤束縛竹爲輿，野飯來尋僧所廬。',32,'全唐诗/poet.song.166000.json','["櫸藤束縛竹爲輿，野飯來尋僧所廬。", "茅屋正逢飛卷破，夜來風雨問何如。"]'),
('59216621-573d-485c-8b2d-d6de5b33429a','過旁羅見靈山','趙蕃','宋','宋诗','song-poetry','','[]','過得旁羅上下灘，望中青出是靈山。',32,'全唐诗/poet.song.166000.json','["過得旁羅上下灘，望中青出是靈山。", "三年此地四來往，老矣向渠成厚顔。"]'),
('bf16d1c6-f095-4f9c-96f6-437b187c1fc7','歸近','趙蕃','宋','宋诗','song-poetry','','[]','黄溪潭上晚風生，吹我孤舟直又橫。',32,'全唐诗/poet.song.166000.json','["黄溪潭上晚風生，吹我孤舟直又橫。", "歸近尚餘三十里，不妨待得月同行。"]'),
('671a9ab1-0be5-40e8-a481-8c7747ecdc30','樓步','趙蕃','宋','宋诗','song-poetry','','[]','人家簇簇曉煙青，湖上船歸漁市腥。',32,'全唐诗/poet.song.166000.json','["人家簇簇曉煙青，湖上船歸漁市腥。", "細雨如絲山色暝，一杯濁酒慰飄零。"]'),
('64bd3673-dbf6-47ee-ab81-53b5bd5a74c9','上饒道中','趙蕃','宋','宋诗','song-poetry','','[]','踏土憂疑似踏船，土塍滑汰勝於舷。',32,'全唐诗/poet.song.166000.json','["踏土憂疑似踏船，土塍滑汰勝於舷。", "川行可怖陸行苦，誰遣爲之空自憐。"]'),
('347c8e3b-3402-45f7-b65e-94f369f2b1e3','過雨市二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','盧溪溪水接宣風，四面青山圖畫中。',32,'全唐诗/poet.song.166000.json','["盧溪溪水接宣風，四面青山圖畫中。", "盡日苦吟吟不足，始知才盡景無窮。"]'),
('7daf2913-fb69-4a38-ae59-b9e4c1a13493','過雨市二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','晴裏看山故自佳，雨邊益覺興無涯。',32,'全唐诗/poet.song.166000.json','["晴裏看山故自佳，雨邊益覺興無涯。", "我家正在千山底，每一看山還自嗟。"]'),
('e966789a-fc66-44fd-9939-62f471ced9f8','書雙逕鋪','趙蕃','宋','宋诗','song-poetry','','[]','昔者曾看紫柞花，今焉梅謝柳生芽。',32,'全唐诗/poet.song.166000.json','["昔者曾看紫柞花，今焉梅謝柳生芽。", "無窮甲子隨車轂，有限光陰屬鬢華。"]'),
('e3e9c86b-fa6f-42fc-8bc1-7cce3bb439b6','題仁坑鋪','趙蕃','宋','宋诗','song-poetry','','[]','四松離立類巖幽，遮我聊爲半日留。',32,'全唐诗/poet.song.166000.json','["四松離立類巖幽，遮我聊爲半日留。", "更恨月明清影夜，不能於此聽颼颼。"]'),
('2d4281c0-196f-4130-9e89-05a679e5675c','發石佛','趙蕃','宋','宋诗','song-poetry','','[]','石佛如今果有靈，盡驅昏翳作空青。',32,'全唐诗/poet.song.166000.json','["石佛如今果有靈，盡驅昏翳作空青。", "松原白石今朝過，雲洞月巖明日經。"]'),
('5b5b39fa-4329-430f-9d31-e1f7983271f7','舒村','趙蕃','宋','宋诗','song-poetry','','[]','有竹如椽故可佳，况於竹外隠鷗沙。',32,'全唐诗/poet.song.166000.json','["有竹如椽故可佳，况於竹外隠鷗沙。", "不嫌官道多車馬，此地端宜著釣車。"]');
